UsageComp._template = "<template tag-name=\"usage-comp\"> <div class=\"zcat-page-wrapper\"> <div class=\"zcat-page-header\"> <h1 class=\"zcat-page-title\">Usage</h1> <p class=\"zcat-page-desc\">Learn how to use ZCAT components in your sLyte application.</p> <div class=\"zcat-page-tabs\"> <span class=\"zcat-page-tab active\">Guide</span> </div> </div> <div class=\"zcat-page-body\"> <div class=\"zcat-page-left\" style=\"max-width:820px;\"> <!-- Overview --> <div class=\"zcat-content-section\"> <h2 class=\"zcat-content-heading\">Basic Usage</h2> <p class=\"zcat-content-text\"> ZCAT components are standard sLyte components. You use them by placing custom element tags in your template HTML and passing configuration via a <strong>zcat-prop</strong> object. </p> <p class=\"zcat-content-text\" style=\"margin-top:8px;\"> Every ZCAT component follows the same pattern: </p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>&lt;zcat-{component}\n  self=\"{{self}}\"\n  zcat-prop=\"{{propObject}}\"\n&gt;&lt;/zcat-{component}&gt;</pre> </div> </div> <!-- ========== BUTTON ========== --> <div class=\"zcat-content-section\" style=\"margin-top:8px;\"> <div style=\"display:flex; align-items:center; gap:8px; margin-bottom:6px;\"> <span style=\"display:inline-flex; align-items:center; justify-content:center; width:28px; height:28px; border-radius:8px; background:var(--zcat-btn-fill-bg-primary-default); color:#fff; font-size:13px; font-weight:600;\">1</span> <h2 class=\"zcat-content-heading\" style=\"margin:0;\">Button</h2> </div> <p class=\"zcat-content-text\">Add a button to your template:</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>&lt;zcat-button\n  self=\"{{self}}\"\n  zcat-prop=\"{{btnProp}}\"\n&gt;&lt;/zcat-button&gt;</pre> </div> <p class=\"zcat-content-text\" style=\"margin-top:12px;\">Configure it in your component's <strong>data()</strong> method:</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>data() {\n  return {\n    self: prop('object', { default: this }),\n    btnProp: prop('object', {\n      default: {\n        label: \"Save Changes\",\n        variant: \"fill\",         // fill | outline | grey | ghost\n        color: \"primary\",        // primary | success | danger\n        size: \"default\",         // default | sm | exsm\n        disabled: false,\n        loading: false,\n        icon: {\n          position: \"left\",      // left | right\n          name: \"\",\n          class: \"icon-class\"\n        },\n        callback: {\n          name: \"onBtnClicked\",  // method name on parent\n          arguments: []\n        }\n      }\n    })\n  };\n}</pre> </div> <!-- Button Props Table --> <div style=\"margin-top:16px; padding:16px; background:var(--zcat-prev-bg); border-radius:10px; border:1px solid var(--zcat-body-border);\"> <p style=\"font-size:13px; font-weight:600; color:var(--zcat-body-text-primary); margin-bottom:10px;\">Button Props</p> <table style=\"width:100%; border-collapse:collapse; font-size:12px;\"> <thead> <tr style=\"border-bottom:1px solid var(--zcat-body-border); text-align:left;\"> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Prop</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Type</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Options</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Default</th> </tr> </thead> <tbody> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>label</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Any text</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>variant</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">fill, outline, grey, ghost</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>color</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">primary, success, danger</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>size</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">default, sm, exsm</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"default\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>disabled</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Boolean</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">true / false</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">false</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>loading</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Boolean</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">true / false</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">false</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>icon</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Object</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{ position, name, class }</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{}</td></tr> <tr><td style=\"padding:6px 10px;\"><code>callback</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Object</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{ name, arguments }</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{}</td></tr> </tbody> </table> </div> </div> <!-- ========== INPUT ========== --> <div class=\"zcat-content-section\" style=\"margin-top:32px;\"> <div style=\"display:flex; align-items:center; gap:8px; margin-bottom:6px;\"> <span style=\"display:inline-flex; align-items:center; justify-content:center; width:28px; height:28px; border-radius:8px; background:var(--zcat-btn-fill-bg-primary-default); color:#fff; font-size:13px; font-weight:600;\">2</span> <h2 class=\"zcat-content-heading\" style=\"margin:0;\">Text Input</h2> </div> <p class=\"zcat-content-text\">Add an input field to your template:</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>&lt;zcat-input\n  self=\"{{self}}\"\n  zcat-prop=\"{{inputProp}}\"\n&gt;&lt;/zcat-input&gt;</pre> </div> <p class=\"zcat-content-text\" style=\"margin-top:12px;\">Configure it in <strong>data()</strong>:</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>data() {\n  return {\n    self: prop('object', { default: this }),\n    inputProp: prop('object', {\n      default: {\n        id: \"username\",\n        type: \"text\",            // text | password | number | email\n        label: \"Username\",\n        placeholder: \"Enter your name\",\n        width: \"300px\",\n        size: \"default\",         // default | sm | exsm\n        variant: \"default\",      // default | ghost\n        state: \"enabled\",        // enabled | disabled | error | readOnly\n        optional: false,\n        labelInfo: false,\n        iconLeft: false,\n        errorMessage: \"This field is required\"\n      }\n    })\n  };\n}</pre> </div> <!-- Input Props Table --> <div style=\"margin-top:16px; padding:16px; background:var(--zcat-prev-bg); border-radius:10px; border:1px solid var(--zcat-body-border);\"> <p style=\"font-size:13px; font-weight:600; color:var(--zcat-body-text-primary); margin-bottom:10px;\">Input Props</p> <table style=\"width:100%; border-collapse:collapse; font-size:12px;\"> <thead> <tr style=\"border-bottom:1px solid var(--zcat-body-border); text-align:left;\"> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Prop</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Type</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Options</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Default</th> </tr> </thead> <tbody> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>id</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Unique identifier</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>type</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">text, password, number, email</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"text\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>label</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Any text</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>placeholder</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Any text</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>width</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">CSS value (e.g. \"300px\")</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"100%\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>size</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">default, sm, exsm</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"default\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>variant</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">default, ghost</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"default\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>state</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">enabled, disabled, error, readOnly</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"enabled\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>optional</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Boolean</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Shows \"(optional)\" label</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">false</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>labelInfo</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Boolean</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Shows info icon next to label</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">false</td></tr> <tr><td style=\"padding:6px 10px;\"><code>errorMessage</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Shown when state is \"error\"</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> </tbody> </table> </div> </div> <!-- ========== DROPDOWN ========== --> <div class=\"zcat-content-section\" style=\"margin-top:32px;\"> <div style=\"display:flex; align-items:center; gap:8px; margin-bottom:6px;\"> <span style=\"display:inline-flex; align-items:center; justify-content:center; width:28px; height:28px; border-radius:8px; background:var(--zcat-btn-fill-bg-primary-default); color:#fff; font-size:13px; font-weight:600;\">3</span> <h2 class=\"zcat-content-heading\" style=\"margin:0;\">Dropdown</h2> </div> <p class=\"zcat-content-text\">Add a dropdown to your template:</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>&lt;zcat-dropdown\n  self=\"{{self}}\"\n  zcat-prop=\"{{dropdownProp}}\"\n&gt;&lt;/zcat-dropdown&gt;</pre> </div> <p class=\"zcat-content-text\" style=\"margin-top:12px;\">Configure it in <strong>data()</strong>:</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>data() {\n  return {\n    self: prop('object', { default: this }),\n    dropdownProp: prop('object', {\n      default: {\n        label: \"Country\",\n        placeholder: \"Select a country\",\n        width: \"300px\",\n        size: \"default\",         // default | sm | exsm\n        variant: \"default\",      // default | ghost\n        state: \"enabled\",        // enabled | disabled | error\n        optional: false,\n        labelInfo: false,\n        iconLeft: false,\n        selected: \"india\",       // pre-selected value\n        options: [\n          { name: \"India\", value: \"india\" },\n          { name: \"Pakistan\", value: \"pakistan\" },\n          { name: \"Sri Lanka\", value: \"srilanka\" }\n        ],\n        showSearch: true,        // search bar in menu\n        menuHeader: \"Choose Country\",\n        showIcon: false,         // icons on menu items\n        createNewBtn: {\n          show: true,\n          label: \"+ Create New\",\n          callback: { name: \"onCreateNew\" }\n        },\n        errorMessage: \"Selection is required\",\n        callback: {\n          name: \"onDropdownSelect\"\n        }\n      }\n    })\n  };\n}</pre> </div> <!-- Dropdown Props Table --> <div style=\"margin-top:16px; padding:16px; background:var(--zcat-prev-bg); border-radius:10px; border:1px solid var(--zcat-body-border);\"> <p style=\"font-size:13px; font-weight:600; color:var(--zcat-body-text-primary); margin-bottom:10px;\">Dropdown Props</p> <table style=\"width:100%; border-collapse:collapse; font-size:12px;\"> <thead> <tr style=\"border-bottom:1px solid var(--zcat-body-border); text-align:left;\"> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Prop</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Type</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Description</th> <th style=\"padding:6px 10px; color:var(--zcat-body-text-grey); font-weight:500;\">Default</th> </tr> </thead> <tbody> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>label</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Field label text</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>placeholder</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Trigger placeholder text</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"Select\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>options</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Array</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">[{ name, value, icon?, disabled? }]</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">[]</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>selected</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Value of pre-selected item</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>size</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">default, sm, exsm</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"default\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>variant</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">default, ghost</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"default\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>state</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">enabled, disabled, error</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"enabled\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>showSearch</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Boolean</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Show search field in menu</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">false</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>menuHeader</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">String</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Header text above menu items</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">\"\"</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>showIcon</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Boolean</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Show icons on menu items</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">false</td></tr> <tr style=\"border-bottom:1px solid var(--zcat-body-border);\"><td style=\"padding:6px 10px;\"><code>createNewBtn</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Object</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{ show, label, callback: { name } }</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{ show: false }</td></tr> <tr><td style=\"padding:6px 10px;\"><code>callback</code></td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">Object</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{ name } — called on select</td><td style=\"padding:6px 10px; color:var(--zcat-body-text-grey);\">{}</td></tr> </tbody> </table> </div> </div> <!-- ========== CALLBACKS ========== --> <div class=\"zcat-content-section\" style=\"margin-top:32px;\"> <h2 class=\"zcat-content-heading\">Handling Callbacks</h2> <p class=\"zcat-content-text\"> ZCAT components fire callbacks on the parent component via the <strong>self</strong> reference. Define callback methods in your component's <strong>methods()</strong> block: </p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>static methods() {\n  return {\n    // Button callback\n    onBtnClicked() {\n      console.log(\"Button was clicked!\");\n    },\n\n    // Dropdown callback — receives the selected item\n    onDropdownSelect(item) {\n      console.log(\"Selected:\", item.name, item.value);\n    },\n\n    // Create new callback from dropdown\n    onCreateNew() {\n      console.log(\"Create new item clicked\");\n    }\n  };\n}</pre> </div> </div> <!-- ========== DARK MODE ========== --> <div class=\"zcat-content-section\" style=\"margin-top:32px;\"> <h2 class=\"zcat-content-heading\">Dark Mode</h2> <p class=\"zcat-content-text\"> Add the <strong>data-user-color-scheme=\"dark\"</strong> attribute to the <code>&lt;html&gt;</code> element. All ZCAT components automatically switch to their dark mode token values. </p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>&lt;html data-user-color-scheme=\"dark\"&gt;</pre> </div> </div> <!-- ========== CUSTOMIZING FONTS ========== --> <div class=\"zcat-content-section\" style=\"margin-top:32px;\"> <h2 class=\"zcat-content-heading\">Customizing Fonts</h2> <p class=\"zcat-content-text\"> Override the <strong>--zcat-font-family-primary</strong> token to use a different font: </p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>:root {\n  --zcat-font-family-primary: 'Inter', sans-serif;\n}</pre> </div> </div> <!-- ========== COMPLETE EXAMPLE ========== --> <div class=\"zcat-content-section\" style=\"margin-top:32px;\"> <h2 class=\"zcat-content-heading\">Complete Example</h2> <p class=\"zcat-content-text\"> Here's a complete sLyte component using all three ZCAT components together: </p> <p class=\"zcat-content-text\" style=\"margin-top:8px; font-size:13px; font-weight:500; color:var(--zcat-body-text-primary);\">Template (my-form.html):</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>&lt;template tag-name=\"my-form\"&gt;\n  &lt;div style=\"padding:24px; display:flex; flex-direction:column; gap:16px;\"&gt;\n\n    &lt;zcat-input\n      self=\"{{self}}\"\n      zcat-prop=\"{{nameProp}}\"\n    &gt;&lt;/zcat-input&gt;\n\n    &lt;zcat-dropdown\n      self=\"{{self}}\"\n      zcat-prop=\"{{countryProp}}\"\n    &gt;&lt;/zcat-dropdown&gt;\n\n    &lt;zcat-button\n      self=\"{{self}}\"\n      zcat-prop=\"{{submitProp}}\"\n    &gt;&lt;/zcat-button&gt;\n\n  &lt;/div&gt;\n&lt;/template&gt;</pre> </div> <p class=\"zcat-content-text\" style=\"margin-top:16px; font-size:13px; font-weight:500; color:var(--zcat-body-text-primary);\">Logic (my-form.js):</p> <div class=\"zcat-code-panel zcat-content-code\"> <pre>import { Component } from '@slyte/component';\nimport { prop } from '@slyte/core';\n\nclass MyForm extends Component {\n  data() {\n    return {\n      self: prop('object', { default: this }),\n      nameProp: prop('object', {\n        default: {\n          id: \"fullname\",\n          label: \"Full Name\",\n          placeholder: \"Enter your name\",\n          width: \"300px\"\n        }\n      }),\n      countryProp: prop('object', {\n        default: {\n          label: \"Country\",\n          placeholder: \"Select country\",\n          width: \"300px\",\n          showSearch: true,\n          options: [\n            { name: \"India\", value: \"india\" },\n            { name: \"USA\", value: \"usa\" },\n            { name: \"UK\", value: \"uk\" }\n          ],\n          callback: { name: \"onCountrySelect\" }\n        }\n      }),\n      submitProp: prop('object', {\n        default: {\n          label: \"Submit\",\n          variant: \"fill\",\n          color: \"primary\",\n          callback: { name: \"onSubmit\" }\n        }\n      })\n    };\n  }\n\n  static methods() {\n    return {\n      onCountrySelect(item) {\n        console.log(\"Country:\", item.name);\n      },\n      onSubmit() {\n        console.log(\"Form submitted!\");\n      }\n    };\n  }\n\n  static actions() { return {}; }\n  static observers() { return {}; }\n}\n\nexport { MyForm };</pre> </div> </div> </div> </div> </div> </template>";;
